-- Leadership Reboot 90-Day Curriculum Seed Data
-- Based on the SIGNAL Leadership Model

-- Clear existing lessons
delete from public.daily_lessons;

-- Insert all 90 days of curriculum
on conflict (day_number) do update set
  focus_area = excluded.focus_area,
  focus_reframe_technique = excluded.focus_reframe_technique,
  leader_example = excluded.leader_example,
  leader_context = excluded.leader_context,
  leader_story_id = excluded.leader_story_id,
  thought_to_work_on = excluded.thought_to_work_on,
  action_for_today = excluded.action_for_today,
  updated_at = timezone('utc'::text, now());
